/**
 * Internet Identity — create an identity with a LEGACY (non-discoverable) passkey.
 *
 * Self-contained: the @icp-sdk/core + borc dependencies are inlined below as a
 * gzipped+base64 IIFE bundle. The script decodes & evaluates them locally so
 * nothing is fetched at runtime — works under identity.ic0.app's strict CSP
 * (`script-src 'self' 'unsafe-inline' 'unsafe-eval'`).
 *
 * Steps:
 *   1. Open https://identity.ic0.app (NOT id.ai — `location.origin` becomes the
 *      passkey's origin metadata; it must point at a legacy domain).
 *   2. Open DevTools → Console.
 *   3. Paste this whole script and approve the OS passkey prompt.
 *   4. The console prints the new identity number.
 *   5. Visit https://id.ai → "use existing identity" → enter that number — the
 *      upgrade flow should fire because no device has origin = id.ai.
 */
(async () => {
  const log = (...a) => console.log("%c[legacy-passkey]", "color:#06c", ...a);

  // 1. Inline dependency bundle (gzip+base64 of an esbuild IIFE).
  log("decompressing dependency bundle…");
  const BUNDLE_GZ_B64 = "";
  const gzBytes = Uint8Array.from(atob(BUNDLE_GZ_B64), (c) => c.charCodeAt(0));
  const ds = new DecompressionStream("gzip");
  const decompressed = await new Response(
    new Blob([gzBytes]).stream().pipeThrough(ds),
  ).arrayBuffer();
  const bundleSrc = new TextDecoder().decode(decompressed);
  new Function(bundleSrc)();
  const {
    HttpAgent,
    Actor,
    Ed25519KeyIdentity,
    wrapDER,
    DER_COSE_OID,
    IDL,
    cborDecode,
    cborEncode,
  } = globalThis.__IIDeps;

  // 2. Resolve canister id.
  const canisterId =
    document.querySelector('meta[name="canister-id"]')?.content ??
    "rdmx6-jaaaa-aaaaa-aaadq-cai";
  log("canister:", canisterId, "origin:", location.origin);
  if (location.hostname.endsWith("id.ai")) {
    console.warn(
      "%c[legacy-passkey] You are on id.ai — passkeys created here will NOT trigger the upgrade flow. Navigate to https://identity.ic0.app first.",
      "color:#c60;font-weight:bold",
    );
  }

  // 3. Minimal IDL covering the three methods we call.
  const MetadataMapV2 = IDL.Rec();
  MetadataMapV2.fill(
    IDL.Vec(
      IDL.Tuple(
        IDL.Text,
        IDL.Variant({
          Map: MetadataMapV2,
          String: IDL.Text,
          Bytes: IDL.Vec(IDL.Nat8),
        }),
      ),
    ),
  );
  const PublicKey = IDL.Vec(IDL.Nat8);
  const CredentialId = IDL.Vec(IDL.Nat8);
  const Aaguid = IDL.Vec(IDL.Nat8);
  const Timestamp = IDL.Nat64;
  const Sec = IDL.Record({
    protection: IDL.Variant({ Protected: IDL.Null, Unprotected: IDL.Null }),
    purpose: IDL.Variant({ Recovery: IDL.Null, Authentication: IDL.Null }),
  });
  const AuthnMethod = IDL.Variant({
    PubKey: IDL.Record({ pubkey: PublicKey }),
    WebAuthn: IDL.Record({
      pubkey: PublicKey,
      aaguid: IDL.Opt(Aaguid),
      credential_id: CredentialId,
    }),
  });
  const AuthnMethodData = IDL.Record({
    security_settings: Sec,
    metadata: MetadataMapV2,
    last_authentication: IDL.Opt(Timestamp),
    authn_method: AuthnMethod,
  });
  const RegFlowNext = IDL.Variant({
    CheckCaptcha: IDL.Record({ captcha_png_base64: IDL.Text }),
    Finish: IDL.Null,
  });
  const NextStepRes = IDL.Record({ next_step: RegFlowNext });
  const StartErr = IDL.Variant({
    InvalidCaller: IDL.Null,
    AlreadyInProgress: IDL.Null,
    RateLimitExceeded: IDL.Null,
  });
  const CapErr = IDL.Variant({
    NoRegistrationFlow: IDL.Null,
    UnexpectedCall: IDL.Record({ next_step: RegFlowNext }),
    WrongSolution: IDL.Record({ new_captcha_png_base64: IDL.Text }),
  });
  const FinErr = IDL.Variant({
    NoRegistrationFlow: IDL.Null,
    UnexpectedCall: IDL.Record({ next_step: RegFlowNext }),
    InvalidAuthnMethod: IDL.Text,
    StorageError: IDL.Text,
  });
  const idlFactory = ({ IDL }) =>
    IDL.Service({
      identity_registration_start: IDL.Func(
        [],
        [IDL.Variant({ Ok: NextStepRes, Err: StartErr })],
        [],
      ),
      check_captcha: IDL.Func(
        [IDL.Record({ solution: IDL.Text })],
        [IDL.Variant({ Ok: NextStepRes, Err: CapErr })],
        [],
      ),
      identity_registration_finish: IDL.Func(
        [
          IDL.Record({
            name: IDL.Opt(IDL.Text),
            authn_method: AuthnMethodData,
          }),
        ],
        [
          IDL.Variant({
            Ok: IDL.Record({ identity_number: IDL.Nat64 }),
            Err: FinErr,
          }),
        ],
        [],
      ),
    });

  // 4. Agent + actor (signed by a throw-away identity).
  const isMainnetGateway =
    /(?:^|\.)(ic0\.app|icp0\.io|icp\.net|internetcomputer\.org|id\.ai)$/.test(
      location.hostname,
    );
  const isLocalhost =
    location.hostname === "127.0.0.1" ||
    location.hostname === "0.0.0.0" ||
    location.hostname.endsWith("localhost");
  const host = isMainnetGateway ? "https://icp-api.io" : location.origin;
  const tempIdentity = Ed25519KeyIdentity.generate();
  const agent = await HttpAgent.create({ identity: tempIdentity, host });
  if (isLocalhost) await agent.fetchRootKey();
  const actor = Actor.createActor(idlFactory, { agent, canisterId });

  // 5. Start registration.
  log("identity_registration_start…");
  const startRes = await actor.identity_registration_start();
  if ("Err" in startRes)
    throw new Error("start: " + JSON.stringify(startRes.Err));
  let nextStep = startRes.Ok.next_step;

  // 6. Captcha loop.
  const showCaptcha = (b64) => {
    document.getElementById("__ii_captcha")?.remove();
    const img = new Image();
    img.id = "__ii_captcha";
    img.src = "data:image/png;base64," + b64;
    img.style.cssText =
      "position:fixed;top:20px;left:20px;z-index:2147483647;background:#fff;padding:8px;border:3px solid #06c;box-shadow:0 4px 16px rgba(0,0,0,.3);";
    document.body.appendChild(img);
    return img;
  };
  while ("CheckCaptcha" in nextStep) {
    const img = showCaptcha(nextStep.CheckCaptcha.captcha_png_base64);
    const solution = prompt("Captcha solution (image overlaid top-left):");
    img.remove();
    if (solution === null) throw new Error("Captcha cancelled");
    const cap = await actor.check_captcha({ solution });
    if ("Err" in cap) {
      if ("WrongSolution" in cap.Err) {
        log("wrong solution, retry");
        nextStep = {
          CheckCaptcha: {
            captcha_png_base64: cap.Err.WrongSolution.new_captcha_png_base64,
          },
        };
        continue;
      }
      throw new Error("captcha: " + JSON.stringify(cap.Err));
    }
    nextStep = cap.Ok.next_step;
  }

  // 7. Create a LEGACY (non-discoverable) WebAuthn credential.
  log("navigator.credentials.create (non-discoverable)…");
  const cred = await navigator.credentials.create({
    publicKey: {
      authenticatorSelection: { userVerification: "preferred" },
      attestation: "direct",
      challenge: crypto.getRandomValues(new Uint8Array(16)),
      pubKeyCredParams: [
        { type: "public-key", alg: -7 },
        { type: "public-key", alg: -257 },
      ],
      rp: { name: "Internet Identity Service" },
      user: {
        id: crypto.getRandomValues(new Uint8Array(16)),
        name: "Internet Identity",
        displayName: "Internet Identity",
      },
      excludeCredentials: [],
    },
  });
  if (cred === null) throw new Error("No credential returned");

  // 8. attestationObject -> authData -> COSE pubkey -> DER-wrapped pubkey.
  const attObj = cborDecode(new Uint8Array(cred.response.attestationObject));
  const authData = new Uint8Array(attObj.authData);
  const view = new DataView(
    authData.buffer,
    authData.byteOffset,
    authData.byteLength,
  );
  const credIdLen = view.getUint16(53, false);
  const aaguid = authData.slice(37, 53);
  const coseRaw = authData.slice(55 + credIdLen);
  const decoded = cborDecode(coseRaw);
  const ALLOWED = new Set([1, 3, -1, -2, -3]);
  const cleaned = new Map();
  for (const [k, v] of decoded.entries()) if (ALLOWED.has(k)) cleaned.set(k, v);
  const coseBytes = new Uint8Array(cborEncode(cleaned));
  const pubKeyDer = new Uint8Array(wrapDER(coseBytes, DER_COSE_OID));

  // 9. Build AuthnMethodData. origin metadata = current (legacy) origin.
  const credentialId = new Uint8Array(cred.rawId);
  const authnMethodData = {
    metadata: [
      ["origin", { String: location.origin }],
      ["alias", { String: "Legacy test passkey" }],
    ],
    authn_method: {
      WebAuthn: {
        pubkey: pubKeyDer,
        credential_id: credentialId,
        aaguid: [aaguid],
      },
    },
    security_settings: {
      protection: { Unprotected: null },
      purpose: { Authentication: null },
    },
    last_authentication: [],
  };

  // 10. Finish.
  log("identity_registration_finish…");
  const fin = await actor.identity_registration_finish({
    authn_method: authnMethodData,
    name: [`Legacy ${new Date().toISOString().slice(0, 10)}`],
  });
  if ("Err" in fin) throw new Error("finish: " + JSON.stringify(fin.Err));

  const identityNumber = fin.Ok.identity_number;
  const credIdB64Url = btoa(String.fromCharCode(...credentialId))
    .replaceAll("+", "-")
    .replaceAll("/", "_")
    .replaceAll("=", "");
  console.log(
    "%c✓ Legacy identity created",
    "color:#0a7;font-weight:bold;font-size:14px",
  );
  console.log("identity number :", identityNumber.toString());
  console.log("origin (in meta):", location.origin);
  console.log("credential id   :", credIdB64Url);
  console.log(
    "%cNow go to https://id.ai, choose \"use existing identity\", enter the identity number above. The upgrade flow should appear.",
    "color:#06c",
  );
  return identityNumber;
})().catch((e) => console.error("[legacy-passkey] failed:", e));
